<?php
require_once __DIR__ . '/posts.php';

function sf_feed_static_preferences(): array { return ['episode_updates'=>70,'music_posts'=>85,'behind_scenes'=>60,'merch_drops'=>45]; }
function sf_feed_preference_keys(): array { return ['episode_updates'=>'Episode Updates','music_posts'=>'Music Posts','behind_scenes'=>'Behind the Scenes','merch_drops'=>'Merch Drops']; }
function sf_feed_follow_targets(): array { return ['creator'=>'Stonefellow Creator','post_type:news'=>'News','post_type:episode'=>'Episode Posts','post_type:music'=>'Music Posts','post_type:merch'=>'Merch Posts','post_type:behind_scenes'=>'Behind Scenes']; }
function sf_feed_member_preferences(int $userId): array { if(!$userId||!sf_eng_table_exists('member_feed_preferences')) return sf_feed_static_preferences(); $prefs=sf_feed_static_preferences(); foreach(sf_eng_fetch_all('SELECT preference_key, weight FROM member_feed_preferences WHERE user_id=?',[$userId]) as $row) $prefs[(string)$row['preference_key']]=(int)$row['weight']; return $prefs; }
function sf_feed_member_follows(int $userId): array { if(!$userId||!sf_eng_table_exists('member_follows')) return []; return sf_eng_fetch_all("SELECT * FROM member_follows WHERE user_id=? AND status='following' ORDER BY created_at DESC",[$userId]); }
function sf_feed_member_follow_map(int $userId): array { $map=[]; foreach(sf_feed_member_follows($userId) as $follow){ $map[(string)$follow['target_type'].':'.(string)($follow['target_slug'] ?: $follow['target_id'] ?: 'creator')]=$follow; } return $map; }
function sf_feed_follow_save(int $userId,string $targetType,string $targetSlug='',int $targetId=0,string $label='',string $status='following'): bool { if(!$userId||!sf_eng_table_exists('member_follows')) return false; if(!in_array($targetType,['creator','post_type','content_type','episode','video','song','album','post','product'],true)) return false; if(!in_array($status,['following','muted'],true)) $status='following'; return sf_eng_execute('INSERT INTO member_follows (user_id,target_type,target_id,target_slug,label,status) VALUES (?,?,?,?,?,?) ON DUPLICATE KEY UPDATE label=VALUES(label), status=VALUES(status), updated_at=NOW()',[$userId,$targetType,$targetId?:null,$targetSlug?:null,$label?:null,$status]); }
function sf_feed_follow_remove(int $userId,string $targetType,string $targetSlug='',int $targetId=0): bool { if(!$userId||!sf_eng_table_exists('member_follows')) return false; return sf_eng_execute('DELETE FROM member_follows WHERE user_id=? AND target_type=? AND COALESCE(target_id,0)=? AND COALESCE(target_slug,"")=?',[$userId,$targetType,$targetId,$targetSlug]); }
function sf_feed_save_preferences(int $userId,array $weights): bool { if(!$userId||!sf_eng_table_exists('member_feed_preferences')) return false; foreach(sf_feed_preference_keys() as $key=>$label){ $weight=max(0,min(100,(int)($weights[$key]??50))); sf_eng_execute('INSERT INTO member_feed_preferences (user_id,preference_key,preference_value,weight) VALUES (?,?,?,?) ON DUPLICATE KEY UPDATE preference_value=VALUES(preference_value), weight=VALUES(weight), updated_at=NOW()',[$userId,$key,$label,$weight]); } return true; }
function sf_feed_item_status(int $userId,int $postId,string $status='shown',int $score=0,string $reason=''): bool { if(!$userId||$postId<=0||!sf_eng_table_exists('member_feed_items')) return false; $field='shown_at'; if($status==='saved')$field='saved_at'; elseif($status==='hidden'||$status==='dismissed')$field='hidden_at'; elseif($status==='clicked'){$status='shown';$field='clicked_at';} return sf_eng_execute("INSERT INTO member_feed_items (user_id,post_id,feed_status,personalization_score,reason,{$field}) VALUES (?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE feed_status=VALUES(feed_status), personalization_score=GREATEST(personalization_score,VALUES(personalization_score)), reason=VALUES(reason), {$field}=NOW(), updated_at=NOW()",[$userId,$postId,$status,$score,$reason?:null]); }
function sf_feed_post_score(array $post,array $prefs,array $followMap): array { $score=50; $reasons=[]; $type=(string)($post['post_type']??'news'); $prefKey=$type==='music'?'music_posts':($type==='episode'?'episode_updates':($type==='behind_scenes'?'behind_scenes':($type==='merch'?'merch_drops':'episode_updates'))); if(isset($prefs[$prefKey])){ $score+=(int)round(((int)$prefs[$prefKey]-50)/2); $reasons[]='Preference: '.($prefs[$prefKey]).'/100'; } if(isset($followMap['creator:creator'])){ $score+=12; $reasons[]='Following creator'; } if(isset($followMap['post_type:'.$type])){ $score+=20; $reasons[]='Following '.str_replace('_',' ',$type); } if(!empty($post['is_featured'])){ $score+=8; $reasons[]='Featured'; } $score+=min(20,(int)($post['comment_count']??0)*2+(int)($post['reaction_count']??0)); return ['score'=>max(0,min(100,$score)),'reason'=>implode(' · ',$reasons) ?: 'Latest post']; }
function sf_feed_personalized_posts(int $userId=0,int $limit=80): array { $posts=sf_posts_all('published',$limit); if(!$posts) return []; $prefs=sf_feed_member_preferences($userId); $followMap=sf_feed_member_follow_map($userId); $hidden=[]; if($userId&&sf_eng_table_exists('member_feed_items')) foreach(sf_eng_fetch_all("SELECT post_id FROM member_feed_items WHERE user_id=? AND feed_status IN ('hidden','dismissed')",[$userId]) as $row) $hidden[(int)$row['post_id']]=true; foreach($posts as &$post){ $rank=sf_feed_post_score($post,$prefs,$followMap); $post['personalization_score']=$rank['score']; $post['personalization_reason']=$rank['reason']; $post['is_saved']=false; if($userId&&sf_eng_table_exists('member_feed_items')){ $item=sf_eng_fetch_one('SELECT feed_status FROM member_feed_items WHERE user_id=? AND post_id=? LIMIT 1',[$userId,(int)($post['id']??0)]); $post['is_saved']=($item['feed_status']??'')==='saved'; } } unset($post); $posts=array_values(array_filter($posts,fn($p)=>empty($hidden[(int)($p['id']??0)]))); usort($posts,fn($a,$b)=>(int)($b['personalization_score']??0)<=> (int)($a['personalization_score']??0) ?: strcmp((string)($b['published_at']??''),(string)($a['published_at']??''))); return array_slice($posts,0,$limit); }
function sf_engagement_analytics_summary(int $days=30): array { $since=date('Y-m-d H:i:s',time()-$days*86400); $out=['posts'=>0,'comments'=>0,'reactions'=>0,'follows'=>0,'saves'=>0,'hides'=>0,'top_posts'=>[],'top_members'=>[]]; if(sf_eng_table_exists('creator_posts')) $out['posts']=(int)(sf_eng_fetch_one("SELECT COUNT(*) AS total FROM creator_posts WHERE status='published'")['total']??0); if(sf_eng_table_exists('fan_comments')) $out['comments']=(int)(sf_eng_fetch_one('SELECT COUNT(*) AS total FROM fan_comments WHERE created_at>=?',[$since])['total']??0); if(sf_eng_table_exists('fan_reactions')) $out['reactions']=(int)(sf_eng_fetch_one('SELECT COUNT(*) AS total FROM fan_reactions WHERE created_at>=?',[$since])['total']??0); if(sf_eng_table_exists('member_follows')) $out['follows']=(int)(sf_eng_fetch_one("SELECT COUNT(*) AS total FROM member_follows WHERE status='following'")['total']??0); if(sf_eng_table_exists('member_feed_items')){ $out['saves']=(int)(sf_eng_fetch_one("SELECT COUNT(*) AS total FROM member_feed_items WHERE feed_status='saved'")['total']??0); $out['hides']=(int)(sf_eng_fetch_one("SELECT COUNT(*) AS total FROM member_feed_items WHERE feed_status IN ('hidden','dismissed')")['total']??0); } if(sf_eng_table_exists('creator_posts')) $out['top_posts']=sf_eng_fetch_all("SELECT p.id,p.title,p.slug,p.post_type, COALESCE(c.comments,0) AS comments, COALESCE(r.reactions,0) AS reactions, COALESCE(f.saves,0) AS saves, (COALESCE(c.comments,0)*4+COALESCE(r.reactions,0)*2+COALESCE(f.saves,0)*5) AS score FROM creator_posts p LEFT JOIN (SELECT content_id,COUNT(*) comments FROM fan_comments WHERE content_type='post' GROUP BY content_id) c ON c.content_id=p.id LEFT JOIN (SELECT target_id,COUNT(*) reactions FROM fan_reactions WHERE target_type='post' GROUP BY target_id) r ON r.target_id=p.id LEFT JOIN (SELECT post_id,COUNT(*) saves FROM member_feed_items WHERE feed_status='saved' GROUP BY post_id) f ON f.post_id=p.id WHERE p.status='published' ORDER BY score DESC,p.published_at DESC LIMIT 12"); if(sf_eng_table_exists('member_engagement_scores')) $out['top_members']=sf_eng_fetch_all('SELECT mes.*, u.email, u.display_name FROM member_engagement_scores mes LEFT JOIN users u ON u.id=mes.user_id ORDER BY mes.score DESC, mes.last_engaged_at DESC LIMIT 12'); return $out; }
function sf_engagement_recalculate_member_scores(): bool { if(!sf_eng_table_exists('member_engagement_scores')||!sf_eng_table_exists('users')) return false; $users=sf_eng_fetch_all('SELECT id FROM users LIMIT 1000'); foreach($users as $u){ $id=(int)$u['id']; $comments=sf_eng_table_exists('fan_comments')?(int)(sf_eng_fetch_one('SELECT COUNT(*) total FROM fan_comments WHERE user_id=?',[$id])['total']??0):0; $reactions=sf_eng_table_exists('fan_reactions')?(int)(sf_eng_fetch_one('SELECT COUNT(*) total FROM fan_reactions WHERE user_id=?',[$id])['total']??0):0; $follows=sf_eng_table_exists('member_follows')?(int)(sf_eng_fetch_one("SELECT COUNT(*) total FROM member_follows WHERE user_id=? AND status='following'",[$id])['total']??0):0; $saves=sf_eng_table_exists('member_feed_items')?(int)(sf_eng_fetch_one("SELECT COUNT(*) total FROM member_feed_items WHERE user_id=? AND feed_status='saved'",[$id])['total']??0):0; $streams=sf_eng_table_exists('audio_play_events')?(int)(sf_eng_fetch_one('SELECT COUNT(*) total FROM audio_play_events WHERE user_id=?',[$id])['total']??0):0; $score=$comments*5+$reactions*2+$follows*3+$saves*4+$streams; sf_eng_execute('INSERT INTO member_engagement_scores (user_id,score,comment_count,reaction_count,save_count,follow_count,stream_count,last_engaged_at) VALUES (?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE score=VALUES(score), comment_count=VALUES(comment_count), reaction_count=VALUES(reaction_count), save_count=VALUES(save_count), follow_count=VALUES(follow_count), stream_count=VALUES(stream_count), last_engaged_at=NOW(), updated_at=NOW()',[$id,$score,$comments,$reactions,$saves,$follows,$streams]); } return true; }
?>
